        *   **For querying (RAG):**
            ```typescript
            interface RagQueryArgs {
              query: string;
              source_filter?: string; // e.g., "ai-sdk.dev"
              match_count?: number;
            }

            async function performRagQuery(args: RagQueryArgs): Promise<any> {
              const mcpServerUrl = 'http://localhost:8051'; // Or your deployed server URL
              // Again, assuming a POST endpoint based on typical FastAPI/MCP
              const response = await fetch(`${mcpServerUrl}/perform_rag_query`, { // Or whatever the endpoint is
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(args),
              });
              if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
              }
              return response.json();
            }

            // Usage example
            async function main() {
              try {
                // First, ensure documentation is crawled
                // await crawlPage('https://ai-sdk.vercel.app/llms.txt'); // Or use smart_crawl_url

                const ragResults = await performRagQuery({
                  query: 'How to stream text from an OpenAI model using Vercel AI SDK?',
                  source_filter: 'ai-sdk.dev', // Filter by the domain you crawled
                  match_count: 3,
                });
                console.log('RAG Results:', JSON.stringify(ragResults, null, 2));

                // If USE_AGENTIC_RAG is true on the server:
                const codeResults = await fetch(`${mcpServerUrl}/search_code_examples`, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({ query: 'OpenAI stream response', source_id: 'ai-sdk.dev' }),
                }).then(res => res.json());
                console.log('Code Examples:', JSON.stringify(codeResults, null, 2));

              } catch (error) {
                console.error('Error in RAG workflow:', error);
              }
            }
            main();
